        <script>
        (function () {
            "use strict";

            function initSwiperCards(container) {
                var swiperEl = container.querySelector(".swiper");
                if (!swiperEl) return;

                new Swiper(swiperEl, {
                    slidesPerView: "auto",
                    spaceBetween: 16,
                    freeMode: true,
                    grabCursor: true,
                    scrollbar: {
                        el: container.querySelector(".swiper-scrollbar"),
                        draggable: true,
                    },
                    navigation: {
                        nextEl: container.querySelector(".swiper-button-next"),
                        prevEl: container.querySelector(".swiper-button-prev"),
                    },
                    breakpoints: {
                        769: {
                            spaceBetween: 130,
                        }
                    },
                });
            }

            function init() {
                var container = document.getElementById("swiper-cards-<?php echo esc_attr($widget_id); ?>");
                if (container) {
                    initSwiperCards(container);
                }
            }

            if (document.readyState === "loading") {
                document.addEventListener("DOMContentLoaded", init);
            } else {
                init();
            }

            if (window.elementorFrontend) {
                window.elementorFrontend.hooks.addAction(
                    "frontend/element_ready/swiper_cards.default",
                    function ($scope) {
                        var container = $scope[0].querySelector(".swiper-cards-widget");
                        if (container) {
                            initSwiperCards(container);
                        }
                    }
                );
            }
        })();
        </script>

